/// <summary>
/// Code added Binay , 21 Jan 2021
/// </summary>
/// <param name = "_fieldId"></param>
public void modifiedField(FieldId _fieldId)
{


    switch(_fieldId)
    {
        case fieldNum(ETGQualitySpecificationLineGroup, MeasurementType) :
            if (this.MeasurementType == CalculationType::Percentage)
            {
                this.FixedValue = 0;
            }
            if (this.MeasurementType == CalculationType::Fixed)
            {
                this.Increment = 0;
                this.MaxRange  = 0;
                this.MinRange  = 0;

            }
            break;


    }

    super(_fieldId);


}

public boolean validateSpecificationLineRange()
{
    ETGQualitySpecificationLineGroup  etgQualitySpecificationLineGroup;
    boolean     ret = true;

    if( this.MinRange > 0 && this.MaxRange > 0 )
    {
        select firstonly RecId  from etgQualitySpecificationLineGroup
            where etgQualitySpecificationLineGroup.RecId != this.RecId
            && etgQualitySpecificationLineGroup.SubGroupId == this.SubGroupId
            && this.MeasurementType == this.MeasurementType
            && this.MinRange > etgQualitySpecificationLineGroup.MinRange
            && this.MaxRange <= etgQualitySpecificationLineGroup.MaxRange;
        if (etgQualitySpecificationLineGroup.RecId)
        {
            ret =  false;

        }
        else

        {
            etgQualitySpecificationLineGroup.clear();
            select firstonly RecId  from etgQualitySpecificationLineGroup
                where etgQualitySpecificationLineGroup.RecId != this.RecId
                    && etgQualitySpecificationLineGroup.SubGroupId == this.SubGroupId
                    && this.MeasurementType == this.MeasurementType
                    &&  etgQualitySpecificationLineGroup.MinRange <= this.MinRange
                    && etgQualitySpecificationLineGroup.MaxRange >= this.MinRange  ;

            if (etgQualitySpecificationLineGroup.RecId)
            {
                ret =  false;

            }
        }

        if ( this.MaxRange < this.MinRange)
        {
            ret = false;
        }


    }

    return ret;
}

/// <summary>
///
/// </summary>
/// <param name = "_fieldIdToCheck"></param>
/// <returns></returns>
public boolean validateField(FieldId _fieldIdToCheck)
{
    boolean ret;
    ret = super(_fieldIdToCheck);

    switch(_fieldIdToCheck)
    {

        case fieldNum(ETGQualitySpecificationLineGroup, MaxRange) :
            if (!this.validateSpecificationLineRange())
            {
                ret = false;
                Error("@ETG:MinandMaxRange");

            }

            break;

    }



    return ret;
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean validateWrite()
{
    boolean ret;


    ret = super();

    if (!this.validateSpecificationLineRange())
    {
        ret = false;
        Error("@ETG:MinandMaxRange");

    }

    return ret;
}
